  <svg viewBox="0 0 700 430" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">トス×オプティミズムPoCタイムライン · 3カ月検証ロードマップ</text>
    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="13" font-weight="700">①最近のタイムライン</text>
      <line x1="70" y1="110" x2="630" y2="110" stroke="rgba(255,255,255,.15)" stroke-width="2"/>
      <circle cx="110" cy="110" r="8" fill="#4ade80"/>
      <text x="110" y="140" fill="#a1a1aa" font-size="12" text-anchor="middle">7/8</text>
      <text x="110" y="158" fill="#fafafa" font-size="12" text-anchor="middle" font-weight="700">トス・オプティミズム提携</text>
      <text x="110" y="90" fill="#71717a" font-size="11" text-anchor="middle">3カ月PoC開始</text>
      <circle cx="320" cy="110" r="8" fill="#f87171"/>
      <text x="320" y="140" fill="#a1a1aa" font-size="12" text-anchor="middle">7/9</text>
      <text x="320" y="158" fill="#fafafa" font-size="12" text-anchor="middle" font-weight="700">韓銀、51%ルール再確認</text>
      <text x="320" y="90" fill="#71717a" font-size="11" text-anchor="middle">国会企財委提出</text>
      <circle cx="520" cy="110" r="8" fill="#facc15"/>
      <text x="520" y="140" fill="#a1a1aa" font-size="12" text-anchor="middle">〜10月</text>
      <text x="520" y="158" fill="#fafafa" font-size="12" text-anchor="middle" font-weight="700">PoC検証終了(見込)</text>
      <text x="520" y="90" fill="#71717a" font-size="11" text-anchor="middle">3検証ポイント結果</text>
      <circle cx="620" cy="110" r="9" fill="#38bdf8" stroke="#fafafa" stroke-width="2"/>
